using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Helpers;

/// <summary>
/// Provides helper methods for creating test infrastructure.
/// </summary>
public static class TestHelper
{
    /// <summary>
    /// Creates a SchoolContext backed by an in-memory database with a unique name.
    /// </summary>
    public static SchoolContext CreateInMemoryContext(string dbName = null)
    {
        dbName ??= Guid.NewGuid().ToString();
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName)
            .Options;
        return new SchoolContext(options);
    }

    /// <summary>
    /// Drains the static NotificationService queue to ensure test isolation.
    /// Must be called in test cleanup since NotificationService uses a shared static queue.
    /// </summary>
    public static void DrainNotificationQueue()
    {
        using var service = new NotificationService();
        while (service.ReceiveNotification() != null) { }
    }

    /// <summary>
    /// Seeds a context with a set of students and returns the context.
    /// </summary>
    public static SchoolContext SeedStudents(SchoolContext context, params Student[] students)
    {
        context.Students.AddRange(students);
        context.SaveChanges();
        return context;
    }

    /// <summary>
    /// Seeds a context with departments and returns the context.
    /// </summary>
    public static SchoolContext SeedDepartments(SchoolContext context, params Department[] departments)
    {
        context.Departments.AddRange(departments);
        context.SaveChanges();
        return context;
    }

    /// <summary>
    /// Creates a Student with required fields populated.
    /// </summary>
    public static Student CreateStudent(string firstName = "John", string lastName = "Doe", DateTime? enrollmentDate = null)
    {
        return new Student
        {
            FirstMidName = firstName,
            LastName = lastName,
            EnrollmentDate = enrollmentDate ?? new DateTime(2023, 9, 1)
        };
    }

    /// <summary>
    /// Creates an Instructor with required fields populated.
    /// </summary>
    public static Instructor CreateInstructor(string firstName = "Jane", string lastName = "Smith", DateTime? hireDate = null)
    {
        return new Instructor
        {
            FirstMidName = firstName,
            LastName = lastName,
            HireDate = hireDate ?? new DateTime(2020, 1, 15),
            CourseAssignments = new List<CourseAssignment>()
        };
    }

    /// <summary>
    /// Creates a Department with required fields populated.
    /// </summary>
    public static Department CreateDepartment(string name = "Engineering", decimal budget = 100000m, int? instructorId = null)
    {
        return new Department
        {
            Name = name,
            Budget = budget,
            StartDate = new DateTime(2023, 1, 1),
            InstructorID = instructorId
        };
    }

    /// <summary>
    /// Creates a Course with required fields populated.
    /// </summary>
    public static Course CreateCourse(int courseId = 1050, string title = "Chemistry", int credits = 3, int departmentId = 0)
    {
        return new Course
        {
            CourseID = courseId,
            Title = title,
            Credits = credits,
            DepartmentID = departmentId
        };
    }
}

