namespace ContosoUniversity.Tests.Services;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _sut;

    [TestInitialize]
    public void Setup()
    {
        _sut = new NotificationService();
        // Drain any leftover notifications from other tests (static queue)
        while (_sut.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        // Drain queue to avoid polluting other tests
        while (_sut.ReceiveNotification() != null) { }
        _sut.Dispose();
    }

    [TestMethod]
    public void SendNotification_EnqueuesNotification()
    {
        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("Admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_IncludesNameInMessage()
    {
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains("John Doe"), $"Message should contain display name. Actual: {notification.Message}");
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        _sut.SendNotification("Student", "42", EntityOperation.CREATE, "Admin");

        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains("ID: 42"), $"Message should contain ID. Actual: {notification.Message}");
    }

    [TestMethod]
    [DataRow(EntityOperation.CREATE, "has been created", DisplayName = "CREATE message")]
    [DataRow(EntityOperation.UPDATE, "has been updated", DisplayName = "UPDATE message")]
    [DataRow(EntityOperation.DELETE, "has been deleted", DisplayName = "DELETE message")]
    public void SendNotification_OperationType_GeneratesCorrectMessage(EntityOperation operation, string expectedFragment)
    {
        _sut.SendNotification("Course", "101", "Chemistry", operation, "System");

        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains(expectedFragment),
            $"Expected message to contain '{expectedFragment}'. Actual: '{notification.Message}'");
    }

    [TestMethod]
    public void SendNotification_WithNullUserName_DefaultsToSystem()
    {
        _sut.SendNotification("Student", "1", EntityOperation.CREATE, null);

        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        var result = _sut.ReceiveNotification();

        Assert.IsNull(result);
    }

    [TestMethod]
    public void ReceiveNotification_DequeuedInFIFOOrder()
    {
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);
        _sut.SendNotification("Student", "2", EntityOperation.UPDATE);
        _sut.SendNotification("Student", "3", EntityOperation.DELETE);

        var first = _sut.ReceiveNotification();
        var second = _sut.ReceiveNotification();
        var third = _sut.ReceiveNotification();

        Assert.AreEqual("1", first.EntityId);
        Assert.AreEqual("2", second.EntityId);
        Assert.AreEqual("3", third.EntityId);
    }

    [TestMethod]
    public void ReceiveNotification_AfterDequeue_QueueIsEmpty()
    {
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        _sut.ReceiveNotification(); // dequeue

        Assert.IsNull(_sut.ReceiveNotification());
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // MarkAsRead is a no-op in the in-memory implementation
        _sut.MarkAsRead(1);
        _sut.MarkAsRead(999);
        // No exception thrown = pass
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAtToCurrentTime()
    {
        var before = DateTime.Now;

        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        var after = DateTime.Now;
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after,
            $"CreatedAt {notification.CreatedAt} should be between {before} and {after}");
    }

    [TestMethod]
    public void SendNotification_SetsOperationAsString()
    {
        _sut.SendNotification("Department", "5", EntityOperation.DELETE);

        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("DELETE", notification.Operation);
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        var service = new NotificationService();

        service.Dispose();
        // No exception = pass
    }

    [TestMethod]
    public void SendNotification_TwoArgOverload_CallsFiveArgOverload()
    {
        // The two-arg overload (without displayName) should pass null for entityDisplayName
        _sut.SendNotification("Instructor", "7", EntityOperation.UPDATE, "Admin");

        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Instructor", notification.EntityType);
        Assert.IsTrue(notification.Message.Contains("ID: 7"), $"Should use ID format. Actual: {notification.Message}");
    }
}

