using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class StudentsControllerTests
{
    private SchoolContext _context;
    private StudentsController _controller;

    [TestInitialize]
    public void Setup()
    {
        TestHelper.DrainNotificationQueue();
        _context = TestHelper.CreateInMemoryContext();
        _controller = new StudentsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        TestHelper.DrainNotificationQueue();
        _controller?.Dispose();
        _context?.Dispose();
    }

    #region Index

    [TestMethod]
    public void Index_NoParams_ReturnsViewWithAllStudents()
    {
        // Arrange
        _context.Students.Add(TestHelper.CreateStudent("Alice", "Adams"));
        _context.Students.Add(TestHelper.CreateStudent("Bob", "Baker"));
        _context.SaveChanges();

        // Act
        var result = _controller.Index(null, null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);
    }

    [TestMethod]
    public void Index_DefaultSort_OrdersByLastNameAscending()
    {
        _context.Students.Add(TestHelper.CreateStudent("Charlie", "Ziegler"));
        _context.Students.Add(TestHelper.CreateStudent("Alice", "Adams"));
        _context.Students.Add(TestHelper.CreateStudent("Bob", "Miller"));
        _context.SaveChanges();

        var result = _controller.Index(null, null, null, null) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.AreEqual("Adams", model[0].LastName);
        Assert.AreEqual("Miller", model[1].LastName);
        Assert.AreEqual("Ziegler", model[2].LastName);
    }

    [TestMethod]
    public void Index_NameDescSort_OrdersByLastNameDescending()
    {
        _context.Students.Add(TestHelper.CreateStudent("Alice", "Adams"));
        _context.Students.Add(TestHelper.CreateStudent("Charlie", "Ziegler"));
        _context.SaveChanges();

        var result = _controller.Index("name_desc", null, null, null) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.AreEqual("Ziegler", model[0].LastName);
        Assert.AreEqual("Adams", model[1].LastName);
    }

    [TestMethod]
    public void Index_DateSort_OrdersByEnrollmentDateAscending()
    {
        _context.Students.Add(TestHelper.CreateStudent("Bob", "Baker", new DateTime(2024, 1, 1)));
        _context.Students.Add(TestHelper.CreateStudent("Alice", "Adams", new DateTime(2023, 1, 1)));
        _context.SaveChanges();

        var result = _controller.Index("Date", null, null, null) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.AreEqual("Adams", model[0].LastName); // 2023 first
        Assert.AreEqual("Baker", model[1].LastName); // 2024 second
    }

    [TestMethod]
    public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
    {
        _context.Students.Add(TestHelper.CreateStudent("Alice", "Adams", new DateTime(2023, 1, 1)));
        _context.Students.Add(TestHelper.CreateStudent("Bob", "Baker", new DateTime(2024, 1, 1)));
        _context.SaveChanges();

        var result = _controller.Index("date_desc", null, null, null) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.AreEqual("Baker", model[0].LastName); // 2024 first
        Assert.AreEqual("Adams", model[1].LastName); // 2023 second
    }

    [TestMethod]
    public void Index_SearchByLastName_FiltersResults()
    {
        _context.Students.Add(TestHelper.CreateStudent("Alice", "Adams"));
        _context.Students.Add(TestHelper.CreateStudent("Bob", "Baker"));
        _context.SaveChanges();

        var result = _controller.Index(null, null, "Adams", null) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Adams", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchByFirstName_FiltersResults()
    {
        _context.Students.Add(TestHelper.CreateStudent("Alice", "Adams"));
        _context.Students.Add(TestHelper.CreateStudent("Bob", "Baker"));
        _context.SaveChanges();

        var result = _controller.Index(null, null, "Bob", null) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Baker", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchString_ResetsPageTo1()
    {
        // When searchString is not null, page should be set to 1
        for (int i = 0; i < 15; i++)
        {
            _context.Students.Add(TestHelper.CreateStudent($"Student{i}", "TestLast"));
        }
        _context.SaveChanges();

        // Even if page=2, new search resets to page 1
        var result = _controller.Index(null, null, "TestLast", 2) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.AreEqual(1, model.PageIndex);
    }

    [TestMethod]
    public void Index_NullSearchWithCurrentFilter_UsesCurrentFilter()
    {
        _context.Students.Add(TestHelper.CreateStudent("Alice", "Adams"));
        _context.Students.Add(TestHelper.CreateStudent("Bob", "Baker"));
        _context.SaveChanges();

        // searchString is null, currentFilter is "Adams" — should use currentFilter
        var result = _controller.Index(null, "Adams", null, null) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.AreEqual(1, model.Count);
    }

    [TestMethod]
    public void Index_SetsViewBagSortParameters()
    {
        _context.Students.Add(TestHelper.CreateStudent("Alice", "Adams"));
        _context.SaveChanges();

        var result = _controller.Index(null, null, null, null) as ViewResult;

        Assert.AreEqual("name_desc", _controller.ViewBag.NameSortParm);
        Assert.AreEqual("Date", _controller.ViewBag.DateSortParm);
    }

    [TestMethod]
    public void Index_WithNameDescSort_NameSortParmIsEmpty()
    {
        _context.Students.Add(TestHelper.CreateStudent("Alice", "Adams"));
        _context.SaveChanges();

        _controller.Index("name_desc", null, null, null);

        // When sortOrder is not empty, NameSortParm should be ""
        Assert.AreEqual("", _controller.ViewBag.NameSortParm);
    }

    [TestMethod]
    public void Index_Pagination_ReturnsCorrectPage()
    {
        // Add more than 10 students (pageSize = 10)
        for (int i = 0; i < 15; i++)
        {
            _context.Students.Add(TestHelper.CreateStudent($"Student{i:D2}", $"Last{i:D2}"));
        }
        _context.SaveChanges();

        var result = _controller.Index(null, null, null, 2) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.AreEqual(2, model.PageIndex);
        Assert.AreEqual(5, model.Count); // 15 - 10 = 5 on page 2
    }

    #endregion

    #region Details

    [TestMethod]
    public void Details_WithNullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);

        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Details_WithValidId_ReturnsViewWithStudent()
    {
        var student = TestHelper.CreateStudent("Alice", "Adams");
        _context.Students.Add(student);
        _context.SaveChanges();

        var result = _controller.Details(student.ID) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual("Adams", model.LastName);
    }

    #endregion

    #region Create

    [TestMethod]
    public void Create_Get_ReturnsViewWithDefaultEnrollmentDate()
    {
        var result = _controller.Create() as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
    }

    [TestMethod]
    public void Create_Post_ValidStudent_SavesAndRedirects()
    {
        var student = TestHelper.CreateStudent("Alice", "Adams", new DateTime(2023, 9, 1));

        var result = _controller.Create(student) as RedirectToActionResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(1, _context.Students.Count());
    }

    [TestMethod]
    public void Create_Post_MinValueDate_AddsModelError()
    {
        var student = TestHelper.CreateStudent("Alice", "Adams", DateTime.MinValue);

        var result = _controller.Create(student) as ViewResult;

        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [TestMethod]
    public void Create_Post_DateBeforeYear1753_AddsModelError()
    {
        var student = TestHelper.CreateStudent("Alice", "Adams", new DateTime(1752, 12, 31));

        var result = _controller.Create(student) as ViewResult;

        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
