    }

    private Instructor SeedInstructorWithCourses()
    {
        var dept = TestHelper.CreateDepartment("Science");
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var course1 = TestHelper.CreateCourse(1001, "Physics", 3, dept.DepartmentID);
        var course2 = TestHelper.CreateCourse(1002, "Chemistry", 4, dept.DepartmentID);
        _context.Courses.AddRange(course1, course2);
        _context.SaveChanges();

        var instructor = TestHelper.CreateInstructor("Jane", "Smith");
        instructor.CourseAssignments = new List<CourseAssignment>
        {
            new CourseAssignment { CourseID = course1.CourseID, Course = course1 }
        };
        instructor.OfficeAssignment = new OfficeAssignment { Location = "Room 101" };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        return instructor;
    }

    #region Index

    [TestMethod]
    public void Index_NoSelection_ReturnsViewWithAllInstructors()
    {
        var instructor = TestHelper.CreateInstructor("Jane", "Smith");
        instructor.CourseAssignments = new List<CourseAssignment>();
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        var result = _controller.Index(null, null) as ViewResult;

        Assert.IsNotNull(result);
