using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class NotificationsControllerTests
{
    private SchoolContext _context;
    private NotificationsController _controller;

    [TestInitialize]
    public void Setup()
    {
        TestHelper.DrainNotificationQueue();
        _context = TestHelper.CreateInMemoryContext();
        _controller = new NotificationsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        TestHelper.DrainNotificationQueue();
        _controller?.Dispose();
        _context?.Dispose();
    }

    [TestMethod]
    public void GetNotifications_EmptyQueue_ReturnsEmptyListWithSuccess()
    {
        var result = _controller.GetNotifications();

        Assert.IsNotNull(result);
        // JsonResult.Value contains the anonymous object
        var value = result.Value;
        Assert.IsNotNull(value);
        // Verify the JSON structure through reflection (anonymous types)
        var successProp = value.GetType().GetProperty("success");
        Assert.IsNotNull(successProp);
        Assert.AreEqual(true, successProp.GetValue(value));

        var countProp = value.GetType().GetProperty("count");
        Assert.IsNotNull(countProp);
        Assert.AreEqual(0, countProp.GetValue(value));
    }

    [TestMethod]
    public void GetNotifications_WithQueuedNotifications_ReturnsNotifications()
    {
        // Arrange - queue up notifications via NotificationService
        var service = new NotificationService();
        service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");
        service.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE, "Admin");

        // Act
        var result = _controller.GetNotifications();

        // Assert
        var value = result.Value;
        Assert.IsNotNull(value);
        var countProp = value.GetType().GetProperty("count");
        Assert.AreEqual(2, countProp.GetValue(value));

        var successProp = value.GetType().GetProperty("success");
        Assert.AreEqual(true, successProp.GetValue(value));
    }

    [TestMethod]
    public void GetNotifications_LimitsTo10Notifications()
    {
        // Arrange - queue up 15 notifications
        var service = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            service.SendNotification("Student", i.ToString(), EntityOperation.CREATE, "System");
        }

        // Act
        var result = _controller.GetNotifications();

        // Assert - should return max 10
        var value = result.Value;
        var countProp = value.GetType().GetProperty("count");
        Assert.AreEqual(10, countProp.GetValue(value));
    }

    [TestMethod]
    public void GetNotifications_LimitsTo10_RemainingStayInQueue()
    {
        // Arrange - queue 15 notifications
        var service = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            service.SendNotification("Student", i.ToString(), EntityOperation.CREATE, "System");
        }

        // Act - first call takes 10
        _controller.GetNotifications();

        // Act - second call takes the remaining 5
        var result2 = _controller.GetNotifications();
        var value2 = result2.Value;
        var countProp = value2.GetType().GetProperty("count");
        Assert.AreEqual(5, countProp.GetValue(value2));
    }

    [TestMethod]
    public void MarkAsRead_ReturnsSuccessJson()
    {
        var result = _controller.MarkAsRead(1);

        Assert.IsNotNull(result);
        var value = result.Value;
        Assert.IsNotNull(value);
        var successProp = value.GetType().GetProperty("success");
        Assert.AreEqual(true, successProp.GetValue(value));
    }

    [TestMethod]
    public void MarkAsRead_WithAnyId_ReturnsSuccess()
    {
        // MarkAsRead is a no-op in-memory, so any ID should succeed
        var result1 = _controller.MarkAsRead(0);
        var result2 = _controller.MarkAsRead(999);

        var success1 = result1.Value.GetType().GetProperty("success").GetValue(result1.Value);
        var success2 = result2.Value.GetType().GetProperty("success").GetValue(result2.Value);
        Assert.AreEqual(true, success1);
        Assert.AreEqual(true, success2);
    }

    [TestMethod]
    public void Index_ReturnsView()
    {
        var result = _controller.Index() as ViewResult;

        Assert.IsNotNull(result);
    }
}

